import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

import { Separator } from "@/components/ui/8bit/separator";

import "@/components/ui/8bit/styles/retro.css";

export interface SocialStat {
  label: string;
  value: string;
}

interface SocialProof1Props {
  className?: string;
  logos?: ReactNode[];
  stats?: SocialStat[];
  subtitle?: string;
  title?: string;
}

const defaultStats: SocialStat[] = [
  { value: "1,700+", label: "GitHub Stars" },
  { value: "50+", label: "Components" },
  { value: "100+", label: "Contributors" },
  { value: "10K+", label: "Downloads" },
];

export default function SocialProof1({
  title = "Trusted by Builders",
  subtitle = "Join thousands of developers shipping retro UIs",
  stats = defaultStats,
  logos,
  className,
}: SocialProof1Props) {
  return (
    <section className={cn("w-full px-4 py-16", className)}>
      <div className="mx-auto max-w-4xl">
        {(title || subtitle) && (
          <div className="mb-10 text-center">
            {title && (
              <h2 className="retro mb-3 font-bold text-2xl tracking-tight md:text-3xl">
                {title}
              </h2>
            )}
            {subtitle && (
              <p className="retro text-muted-foreground text-[9px]">{subtitle}</p>
            )}
          </div>
        )}

        {/* Stats row */}
        <div className="mb-10 flex flex-wrap items-center justify-center gap-8 md:gap-12">
          {stats.map((stat, idx) => (
            <div key={stat.label}>
              <div className="flex items-center gap-8 md:gap-12">
                <div className="text-center">
                  <div className="retro font-bold text-2xl md:text-3xl">
                    {stat.value}
                  </div>
                  <div className="retro mt-1 text-muted-foreground text-[10px]">
                    {stat.label}
                  </div>
                </div>
                {idx < stats.length - 1 && (
                  <Separator className="hidden h-8 md:block" orientation="vertical" />
                )}
              </div>
            </div>
          ))}
        </div>

        {/* Logo cloud */}
        {logos && logos.length > 0 && (
          <div className="flex flex-wrap items-center justify-center gap-8 opacity-60">
            {logos.map((logo, idx) => (
              <div className="flex items-center" key={`logo-${idx}`}>
                {logo}
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

@import url("https://fonts.googleapis.com/css2?family=Press+Start+2P&display=swap");

.retro {
  font-family:
    "Press Start 2P",
    system-ui,
    -apple-system,
    sans-serif;
  line-height: 1.5;
  letter-spacing: 0.5px;
}

.pixelated {
  image-rendering: pixelated;
  image-rendering: crisp-edges;
}

"use client";

import type * as React from "react";

import * as SeparatorPrimitive from "@radix-ui/react-separator";

import { cn } from "@/lib/utils";

function Separator({
  className,
  orientation = "horizontal",
  decorative = true,
  ...props
}: React.ComponentProps<typeof SeparatorPrimitive.Root>) {
  return (
    <SeparatorPrimitive.Root
      data-slot="separator-root"
      decorative={decorative}
      orientation={orientation}
      className={cn(
        "data-[orientation=horizontal]:bg-[length:16px_8px] data-[orientation=horizontal]:bg-[linear-gradient(90deg,var(--foreground)_75%,transparent_75%)] dark:data-[orientation=horizontal]:bg-[linear-gradient(90deg,var(--ring)_75%,transparent_75%)] shrink-0 data-[orientation=horizontal]:h-0.5 data-[orientation=horizontal]:w-full data-[orientation=vertical]:h-full data-[orientation=vertical]:w-0.5 data-[orientation=vertical]:bg-[length:2px_16px] data-[orientation=vertical]:bg-[linear-gradient(0deg,var(--foreground)_75%,transparent_75%)] dark:data-[orientation=vertical]:bg-[linear-gradient(0deg,var(--ring)_75%,transparent_75%)]",
        className
      )}
      {...props}
    />
  );
}

export { Separator };
